import{_ as t,o as i,c as r,a2 as e}from"./chunks/framework.ZhLefgN8.js";const k=JSON.parse('{"title":"出金到香港银行卡","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"withdrawal/to-hk-bank-card.md","filePath":"zh-CN/withdrawal/to-hk-bank-card.md"}'),l={name:"withdrawal/to-hk-bank-card.md"};function o(n,a,h,d,s,c){return i(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="出金到香港银行卡" tabindex="-1">出金到香港银行卡 <a class="header-anchor" href="#出金到香港银行卡" aria-label="Permalink to &quot;出金到香港银行卡&quot;">​</a></h1><p>系统会根据银行卡类型自动匹配出金方式：港币默认使用 FPS 转数快，美元使用网银转账，民生银行使用银证转账。</p><p>费率和限额说明见 <a href="/wiki/withdrawal/hk-online-banking">网银出金</a>。</p><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>确认可提取的币种和金额（提取资金页会显示最大可提金额，仅为当前币种，不含其他币种）</li><li>确认银行卡账户类型与提取币种匹配：港元需港元账户或综合账户，美元需美元账户或综合账户</li><li>确认银行卡已完成认证（未完成入金见证的银行卡需先入金认证）</li><li>打开长桥 App，进入 <strong>资产 → 全部功能 → 提取资金</strong>，选择币种和收款银行卡，提交申请</li><li>在<strong>提取资金 → 右上角提取记录</strong>查看进度</li></ol><h2 id="开通余额通时的出金" tabindex="-1">开通余额通时的出金 <a class="header-anchor" href="#开通余额通时的出金" aria-label="Permalink to &quot;开通余额通时的出金&quot;">​</a></h2><p>如已开通余额通，提取金额会分为「现金可提」和「最大可提」：</p><ul><li>如提取金额在「现金可提」范围内，按正常时效出金</li><li>如提取金额超过「现金可提」（包含余额通资金），系统自动赎回对应余额通基金（赎回需 2 个交易日），赎回到账后自动出金</li></ul><p>也可先在余额通基金页面手动申请赎回，待赎回成功后再单独出金。</p><h2 id="出金失败时" tabindex="-1">出金失败时 <a class="header-anchor" href="#出金失败时" aria-label="Permalink to &quot;出金失败时&quot;">​</a></h2><p>在<strong>提取资金 → 右上角提取记录</strong>中点击该条记录查看失败原因。如银行卡信息填写错误，在<strong>资产 → 银行卡</strong>中修改后重新提交出金申请。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/withdrawal/hk-online-banking">网银出金</a> — 出金规则与费用详情</li><li><a href="/wiki/deposit/银行卡绑定与审核">银行卡绑定与审核</a> — 银行卡绑定与认证要求</li></ul>',13)])])}const u=t(l,[["render",o]]);export{k as __pageData,u as default};
